SELECT [Purch_ Price Model Item].[Model Item No_], [Item].[Product Family], [Item].[Product Sex], [Purch_ Price Model Item].[Variable Group 02], Min([Purch_ Price Model Item].[Variable Code 02]) AS FromSize, Max([Purch_ Price Model Item].[Variable Code 02]) AS ToSize, Val([Direct Unit Cost]) AS PurchPrice, [Purch_ Price Model Item].[Currency Code], [Item].[Trademark Code], [Item].Description, [Purch_ Price Model Item].[Variable Group 01], [Purch_ Price Model Item].[Variable Code 01], [Variable Code].Description, [Item].[Line Code], Str(Min(Val([Purch_ Price Model Item].[variable code 02]))) & "-" & Str(Max(Val([Purch_ Price Model Item].[variable code 02]))) AS SizeRange
FROM ([Purch_ Price Model Item] INNER JOIN Item ON [Purch_ Price Model Item].[Model Item No_] = [Item].No_) INNER JOIN [Variable Code] ON ([Purch_ Price Model Item].[Variable Group 01] = [Variable Code].[Variable Group]) AND ([Purch_ Price Model Item].[Variable Code 01] = [Variable Code].[Variable Code])
GROUP BY [Purch_ Price Model Item].[Model Item No_], [Item].[Product Family], [Item].[Product Sex], [Purch_ Price Model Item].[Variable Group 02], Val([Direct Unit Cost]), [Purch_ Price Model Item].[Currency Code], [Item].[Trademark Code], [Item].Description, [Purch_ Price Model Item].[Variable Group 01], [Purch_ Price Model Item].[Variable Code 01], [Variable Code].Description, [Item].[Line Code]
HAVING ((([Purch_ Price Model Item].[Variable Group 02])<>"") AND (([Item].[Trademark Code])="THK"));

